arguments.file_text:
@using sv_c3585352ebac4f47bb17459e173f9e1e.Models

<div class="step-indicator d-flex justify-content-between mb-4">
    @for (int i = 0; i < StepNames.Length; i++)
    {
        var stepIndex = i;
        var status = stepIndex == CurrentStep ? "active"
                   : stepIndex < CurrentStep ? "completed"
                   : "upcoming";
        <div class="step-item text-center flex-fill @status"
             role="button"
             @onclick="() => OnStepClick(stepIndex)">
            <div class="step-circle mx-auto mb-1 @status">
                @if (status == "completed")
                {
                    <span>&#10003;</span>
                }
                else
                {
                    <span>@(stepIndex + 1)</span>
                }
            </div>
            <small class="step-label">@StepNames[stepIndex]</small>
        </div>
        @if (stepIndex < StepNames.Length - 1)
        {
            <div class="step-connector align-self-start mt-3 flex-fill @(stepIndex < CurrentStep ? "completed" : "")"></div>
        }
    }
</div>

@code {
    private static readonly string[] StepNames =
    {
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    };

    [Parameter] public int CurrentStep { get; set; }
    [Parameter] public EventCallback<int> OnNavigate { get; set; }

    private async Task OnStepClick(int step)
    {
        if (step < CurrentStep)
        {
            await OnNavigate.InvokeAsync(step);
        }
    }
}

.step-indicator {
    padding: 0 1rem;
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.875rem;
    transition: all 0.2s ease;
}

.step-circle.upcoming {
    background-color: #e9ecef;
    color: #6c757d;
}

.step-circle.active {
    background-color: #0d6efd;
    color: #fff;
}

.step-circle.completed {
    background-color: #198754;
    color: #fff;
}

.step-item {
    cursor: default;
    min-width: 80px;
}

.step-item.completed {
    cursor: pointer;
}

.step-item.upcoming .step-label {
    color: #adb5bd;
}

.step-item.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step-item.completed .step-label {
    color: #198754;
}

.step-connector {
    height: 2px;
    background-color: #e9ecef;
    margin-top: 18px !important;
    max-width: 60px;
}

.step-connector.completed {
    background-color: #198754;
}

