<div class="step-indicator d-flex justify-content-between mb-4">
    @for (int i = 0; i < StepNames.Length; i++)
    {
        var stepIndex = i;
        var status = stepIndex == CurrentStep ? "active"
                   : stepIndex < CurrentStep ? "completed"
                   : "upcoming";
        <div class="step-item text-center flex-fill @status"
             role="button"
             @onclick="() => OnStepClick(stepIndex)">
            <div class="step-circle mx-auto mb-1 @status">
                @if (status == "completed")
                {
                    <span>&#10003;</span>
                }
                else
                {
                    <span>@(stepIndex + 1)</span>
                }
            </div>
            <small class="step-label">@StepNames[stepIndex]</small>
        </div>
        @if (stepIndex < StepNames.Length - 1)
        {
            <div class="step-connector align-self-start mt-3 flex-fill @(stepIndex < CurrentStep ? "completed" : "")"></div>
        }
    }
</div>

@code {
    private static readonly string[] StepNames =
    {
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    };

    [Parameter] public int CurrentStep { get; set; }
    [Parameter] public EventCallback<int> OnNavigate { get; set; }

    private async Task OnStepClick(int step)
    {
        if (step < CurrentStep)
        {
            await OnNavigate.InvokeAsync(step);
        }
    }
}

