@using sv_c3585352ebac4f47bb17459e173f9e1e.Models

<EditForm Model="Model" OnValidSubmit="HandleNext">
    <DataAnnotationsValidator />
    <h4 class="mb-3">Personal Information</h4>

    <div class="row g-3">
        <div class="col-md-6">
            <label class="form-label">Full Name *</label>
            <InputText class="form-control" @bind-Value="Model.FullName" />
            <ValidationMessage For="() => Model.FullName" />
        </div>
        <div class="col-md-6">
            <label class="form-label">Email *</label>
            <InputText class="form-control" @bind-Value="Model.Email" />
            <ValidationMessage For="() => Model.Email" />
            @if (!string.IsNullOrEmpty(emailError))
            {
                <div class="text-danger mt-1">@emailError</div>
            }
        </div>
        <div class="col-md-6">
            <label class="form-label">Phone *</label>
            <InputText class="form-control" @bind-Value="Model.Phone" />
            <ValidationMessage For="() => Model.Phone" />
        </div>
        <div class="col-md-6">
            <label class="form-label">Address *</label>
            <InputText class="form-control" @bind-Value="Model.Address" />
            <ValidationMessage For="() => Model.Address" />
        </div>
    </div>

    <div class="d-flex justify-content-end mt-4">
        <button type="submit" class="btn btn-primary" disabled="@isValidating">
            @if (isValidating)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
                <span>Validating…</span>
            }
            else
            {
                <span>Next</span>
            }
        </button>
    </div>
</EditForm>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public IApplicationService ApplicationService { get; set; } = default!;

    private string? emailError;
    private bool isValidating;

    private async Task HandleNext()
    {
        emailError = null;
        isValidating = true;

        try
        {
            var isValid = await ApplicationService.ValidateEmailAsync(Model.Email);
            if (!isValid)
            {
                emailError = "This email address could not be validated.";
                return;
            }

            await OnNext.InvokeAsync();
        }
        finally
        {
            isValidating = false;
        }
    }
}

@using sv_c3585352ebac4f47bb17459e173f9e1e.Models

<EditForm Model="this" OnValidSubmit="HandleNext">
    <ObjectGraphDataAnnotationsValidator />
    <h4 class="mb-3">Work History</h4>

    @for (int i = 0; i < Entries.Count; i++)
    {
        var index = i;
        <WorkEntryForm Entry="Entries[index]"
                       PositionNumber="index + 1"
                       ShowRemove="Entries.Count > 1"
                       OnRemove="() => RemoveEntry(index)" />
    }

    <button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
        + Add Another Position
    </button>

    <div class="d-flex justify-content-between mt-3">
        <button type="button" class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
        <button type="submit" class="btn btn-primary">Next</button>
    </div>
</EditForm>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private void AddEntry() => Entries.Add(new WorkEntryModel());

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
        {
            Entries.RemoveAt(index);
        }
    }

    private async Task HandleNext() => await OnNext.InvokeAsync();
}

@using sv_c3585352ebac4f47bb17459e173f9e1e.Models

<EditForm Model="this" OnValidSubmit="HandleNext">
    <ObjectGraphDataAnnotationsValidator />
    <h4 class="mb-3">References</h4>
    <p class="text-muted">Please provide 2–3 professional references.</p>

    @for (int i = 0; i < References.Count; i++)
    {
        var index = i;
        <ReferenceForm Reference="References[index]"
                       ReferenceNumber="index + 1"
                       ShowRemove="References.Count > 2"
                       OnRemove="() => RemoveReference(index)" />
    }

    @if (References.Count < 3)
    {
        <button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddReference">
            + Add Reference
        </button>
    }

    <div class="d-flex justify-content-between mt-3">
        <button type="button" class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
        <button type="submit" class="btn btn-primary">Next</button>
    </div>
</EditForm>

@code {
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private void AddReference()
    {
        if (References.Count < 3)
        {
            References.Add(new ReferenceModel());
        }
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
        {
            References.RemoveAt(index);
        }
    }

    private async Task HandleNext() => await OnNext.InvokeAsync();
}

@using sv_c3585352ebac4f47bb17459e173f9e1e.Models

<h4 class="mb-3">Review Your Application</h4>

@if (IsSubmitted)
{
    <div class="alert alert-success text-center py-4">
        <h5 class="mb-2">&#10003; Application Submitted Successfully!</h5>
        <p class="mb-0">Your application ID is <strong>#@ApplicationId</strong>. We'll be in touch soon.</p>
    </div>
}
else
{
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(0)">Edit</button>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6"><strong>Name:</strong> @Personal.FullName</div>
                <div class="col-md-6"><strong>Email:</strong> @Personal.Email</div>
                <div class="col-md-6"><strong>Phone:</strong> @Personal.Phone</div>
                <div class="col-md-6"><strong>Address:</strong> @Personal.Address</div>
            </div>
        </div>
    </div>

    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work History</strong>
            <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(1)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var entry in WorkEntries)
            {
                <div class="mb-3 pb-3 border-bottom">
                    <div><strong>@entry.Title</strong> at @entry.Company</div>
                    <div class="text-muted">
                        @entry.StartDate?.ToString("MMM yyyy") –
                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                    </div>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p class="mt-1 mb-0">@entry.Description</p>
                    }
                </div>
            }
        </div>
    </div>

    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>References</strong>
            <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(2)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var r in References)
            {
                <div class="mb-2">
                    <strong>@r.Name</strong> (@r.Relationship) — @r.Email, @r.Phone
                </div>
            }
        </div>
    </div>

    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Cover Letter</strong>
            <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(3)">Edit</button>
        </div>
        <div class="card-body">
            <p style="white-space: pre-wrap;">@CoverLetter</p>
        </div>
    </div>

    <div class="d-flex justify-content-between mt-4">
        <button type="button" class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
        <button type="button" class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@isSubmitting">
            @if (isSubmitting)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
                <span>Submitting…</span>
            }
            else
            {
                <span>Submit Application</span>
            }
        </button>
    </div>

    @if (!string.IsNullOrEmpty(submitError))
    {
        <div class="alert alert-danger mt-3">@submitError</div>
    }
}

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<int> OnEdit { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnSubmit { get; set; }
    [Parameter] public bool IsSubmitted { get; set; }
    [Parameter] public int ApplicationId { get; set; }

    private bool isSubmitting;
    private string? submitError;

    private async Task HandleSubmit()
    {
        isSubmitting = true;
        submitError = null;

        try
        {
            await OnSubmit.InvokeAsync();
        }
        catch (Exception ex)
        {
            submitError = $"Submission failed: {ex.Message}";
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

