@using System.ComponentModel.DataAnnotations

<EditForm Model="Entries" OnSubmit="HandleNext">
    <h4 class="mb-3">Work History</h4>

    @if (validationErrors.Count > 0)
    {
        <div class="alert alert-danger">
            <ul class="mb-0">
                @foreach (var error in validationErrors)
                {
                    <li>@error</li>
                }
            </ul>
        </div>
    }

    @for (int i = 0; i < Entries.Count; i++)
    {
        var index = i;
        <WorkEntryForm Entry="Entries[index]"
                       PositionNumber="index + 1"
                       ShowRemove="Entries.Count > 1"
                       OnRemove="() => RemoveEntry(index)" />
    }

    <button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
        + Add Another Position
    </button>

    <div class="d-flex justify-content-between mt-3">
        <button type="button" class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
        <button type="submit" class="btn btn-primary">Next</button>
    </div>
</EditForm>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private List<string> validationErrors = new();

    private void AddEntry() => Entries.Add(new WorkEntryModel());

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
        {
            Entries.RemoveAt(index);
        }
    }

    private async Task HandleNext()
    {
        validationErrors.Clear();
        for (int i = 0; i < Entries.Count; i++)
        {
            var ctx = new ValidationContext(Entries[i]);
            var results = new List<ValidationResult>();
            if (!Validator.TryValidateObject(Entries[i], ctx, results, true))
            {
                foreach (var r in results)
                {
                    validationErrors.Add($"Position {i + 1}: {r.ErrorMessage}");
                }
            }
        }

        if (validationErrors.Count == 0)
        {
            await OnNext.InvokeAsync();
        }
    }
}

